#include <stdio.h>
#include <stdlib.h>

// Define structuring elements
int b1[3][3] = {{0, 1, 0}, {1, 1, 1}, {0, 1, 0}};
int b2[3][3] = {{1, 0, 1}, {0, 0, 0}, {1, 0, 1}};

// Function to erode image with structuring element
void erode(int image[3][3], int se[3][3], int result[3][3]) {
  for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
      result[i][j] = 0;
      for (int k = 0; k < 3; k++) {
        for (int l = 0; l < 3; l++) {
          if (se[k][l] == 1 && image[i + k - 1][j + l - 1] == 255) {
            result[i][j] = 255;
          }
        }
      }
    }
  }
}

// Function to perform hit-or-miss transform
void hit_or_miss_transform(int image[3][3], int result[3][3]) {
  int eroded_image[3][3];
  int eroded_complement_image[3][3];
  erode(image, b1, eroded_image);
  erode(image, b2, eroded_complement_image);
  for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
      result[i][j] = eroded_image[i][j] & eroded_complement_image[i][j];
    }
  }
}

int main() {
  int image[3][3] = {{0, 0, 0}, {0, 255, 0}, {0, 0, 0}};
  int result[3][3];
  hit_or_miss_transform(image, result);
  for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
      printf("%d ", result[i][j]);
    }
    printf("\n");
  }
  return 0;
}
